    10→// Notification is the payload sent through all notification channels.
    11→type Notification struct {
    12→	Title   string `json:"title"`
    13→	Body    string `json:"body"`
    14→	Version string `json:"version"`
    15→}
    16→
    17→// Sender is the interface that all notification channel implementations must satisfy.
    18→type Sender interface {
    19→	Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error
    20→}
    21→
    22→// rawBodyFields contains the human-readable fields extracted from raw release JSON.
    23→type rawBodyFields struct {
    24→	Changelog  string
    25→	ReleaseURL string
    26→}
    27→
    28→// parseRawBody extracts known fields from a raw JSON release body.
    29→func parseRawBody(body string) (rawBodyFields, bool) {
    30→	var raw map[string]interface{}
    31→	if err := json.Unmarshal([]byte(body), &raw); err != nil {
    32→		return rawBodyFields{}, false
    33→	}
    34→
    35→	fields := rawBodyFields{
    36→		Changelog:  stringField(raw, "changelog"),
    37→		ReleaseURL: stringField(raw, "release_url"),
    38→	}
    39→
    40→	if fields.Changelog == "" && fields.ReleaseURL == "" {
    41→		return fields, false
    42→	}
    43→	return fields, true
    44→}
    45→
    46→func stringField(m map[string]interface{}, key string) string {
    47→	v, _ := m[key].(string)
    48→	return v
    49→}
    50→

