    26→}
    27→
    28→// NotifyWorker is a River worker that processes NotifyJobArgs.
    29→// It looks up the release, finds all source-level subscriptions, resolves
    30→// the notification channel for each, and dispatches via the appropriate sender.
    31→// After sending notifications, it checks the project's agent rules and
    32→// auto-triggers an agent run if the version criteria are met.
    33→type NotifyWorker struct {
    34→	river.WorkerDefaults[queue.NotifyJobArgs]
    35→	store   NotifyStore
    36→	senders map[string]Sender
    37→}
    38→
    39→// NewSenders returns the default sender map for webhook, Slack, and Discord.
    40→func NewSenders() map[string]Sender {
    41→	return map[string]Sender{
    42→		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    43→		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    44→		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    45→	}
    46→}
    47→
    48→// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    49→func NewNotifyWorker(store NotifyStore) *NotifyWorker {
    50→	return &NotifyWorker{
    51→		store:   store,
    52→		senders: NewSenders(),
    53→	}
    54→}
    55→
    56→// VersionPassesFilter returns true if the version string passes the source's
    57→// include/exclude regex filters. When both are nil the version always passes.
    58→func VersionPassesFilter(version string, include, exclude *string) bool {
    59→	if include != nil && *include != "" {
    60→		matched, err := regexp.MatchString(*include, version)
    61→		if err != nil || !matched {
    62→			return false
    63→		}
    64→	}
    65→	if exclude != nil && *exclude != "" {
    66→		matched, err := regexp.MatchString(*exclude, version)
    67→		if err != nil || matched {
    68→			return false
    69→		}
    70→	}
    71→	return true
    72→}
    73→
    74→// Work processes a notify job: fetches the release, resolves subscriptions,
    75→// sends notifications to all matching channels, and checks agent rules to
    76→// auto-trigger agent runs when version criteria are met.
    77→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    78→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    79→	if err != nil {
    80→		return fmt.Errorf("get release: %w", err)
    81→	}
    82→
    83→	// Check source version filters — skip entirely if filtered out.
    84→	source, err := w.store.GetSource(ctx, job.Args.SourceID)
    85→	if err != nil {
    86→		return fmt.Errorf("get source: %w", err)
    87→	}
    88→	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
    89→		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
    90→		return nil
    91→	}
    92→
    93→	// Check exclude_prereleases — skip if source excludes prereleases and this is one.
    94→	if source.ExcludePrereleases {
    95→		var rawData map[string]interface{}
    96→		if err := json.Unmarshal(release.RawData, &rawData); err == nil {
    97→			if prerelease, _ := rawData["prerelease"].(string); prerelease == "true" {
    98→				slog.Debug("release filtered by exclude_prereleases", "version", release.Version, "source_id", job.Args.SourceID)
    99→				return nil
   100→			}
   101→		}
   102→	}
   103→
   104→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
   105→	if err != nil {
   106→		return fmt.Errorf("list subscriptions: %w", err)
   107→	}
   108→
   109→	for _, sub := range subs {
   110→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
   111→		if err != nil {
   112→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
   113→			continue
   114→		}
   115→
   116→		sender, ok := w.senders[ch.Type]
   117→		if !ok {
   118→			slog.Warn("unknown channel type", "type", ch.Type)
   119→			continue
   120→		}
   121→
   122→		msg := Notification{
   123→			Title:   fmt.Sprintf("New release: %s", release.Version),
   124→			Body:    string(release.RawData),
   125→			Version: release.Version,
   126→		}
   127→
   128→		if err := sender.Send(ctx, ch, msg); err != nil {
   129→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
   130→		}
   131→	}
   132→
   133→	// Check agent rules and auto-trigger if criteria are met.
   134→	w.checkAgentRules(ctx, release, source)
   135→
   136→	return nil
   137→}
   138→
   139→// checkAgentRules evaluates the project's agent rules against the new release
   140→// and the previous release for this source. If any rule matches, an agent run
   141→// is enqueued. Errors are logged but do not fail the job — notification delivery
   142→// is the primary responsibility.
   143→func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
   144→	project, err := w.store.GetProject(ctx, source.ProjectID)
   145→	if err != nil {
   146→		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
   147→		return
   148→	}
   149→
   150→	// Parse the project's agent_rules JSON.
   151→	var rules models.AgentRules
   152→	if len(project.AgentRules) > 0 {
   153→		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
   154→			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   155→			return
   156→		}
   157→	}
   158→
   159→	// Determine the previous version for comparison.
   160→	var previousVersion string
   161→	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
   162→	if err != nil {
   163→		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
   164→		return
   165→	}
   166→	if prev != nil {
   167→		previousVersion = prev.Version
   168→	}
   169→
   170→	if CheckAgentRules(&rules, release.Version, previousVersion) {
   171→		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   172→		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   173→			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   174→		} else {
   175→			slog.Info("agent run triggered by version rules",
   176→				"project_id", source.ProjectID,
   177→				"version", release.Version,
   178→				"previous_version", previousVersion,
   179→			)
   180→		}
   181→	}
   182→}
