    74→export function ReleaseDetail() {
    75→  // Read ID from URL path — useParams() returns stale "0" in static export
    76→  const id = getPathSegment(1); // /releases/{id}
    77→  /* Fetch release */
    78→  const { data: releaseData, isLoading } = useSWR(`release-${id}`, () =>
    79→    releasesApi.get(id)
    80→  );
    81→
    82→  const release = releaseData?.data;
    83→
    84→  /* Fetch source info once we have the release */
    85→  const { data: sourceData } = useSWR(
    86→    release ? `source-${release.source_id}` : null,
    87→    () => (release ? sourcesApi.get(release.source_id) : null)
    88→  );
    89→  const source: Source | undefined = sourceData?.data;
    90→
    91→  /* Fetch project info once we have the source */
    92→  const { data: projectData } = useSWR(
    93→    source ? `project-${source.project_id}` : null,
    94→    () => (source ? projectsApi.get(source.project_id) : null)
    95→  );
    96→  const project: Project | undefined = projectData?.data;
    97→
    98→  /* Fetch linked semantic releases (via project) */
    99→  const { data: srData } = useSWR(
   100→    source ? `sr-for-release-${id}` : null,
   101→    async () => {
   102→      if (!source) return [];
   103→      const res = await srApi.list(source.project_id, 1).catch(() => null);
   104→      if (!res?.data) return [];
   105→      /* Filter semantic releases whose version matches this release version */
   106→      return res.data.filter((sr: SemanticRelease) => sr.version === release?.version);
   107→    }
   108→  );
   109→
   110→  const linkedSRs: SemanticRelease[] = srData ?? [];
   111→
   112→  /* Memoize changelog HTML conversion */
   113→  const changelogHtml = useMemo(() => {
   114→    const raw = release?.raw_data?.changelog;
   115→    if (!raw) return null;
   116→    return changelogToHtml(String(raw));
   117→  }, [release?.raw_data?.changelog]);
   118→
   119→  /* Loading state */
   120→  if (isLoading) {
   121→    return (
   122→      <div
   123→        className="py-16 text-center"
   124→        style={{
   125→          fontFamily: "var(--font-dm-sans)",
   126→          fontSize: "13px",
   127→          color: "#6b7280",
   128→        }}
   129→      >
   130→        Loading...
   131→      </div>
   132→    );
   133→  }
   134→
