	switch strings.ToLower(provider) {
	case "github":
		return "GitHub"
	case "dockerhub":
		return "Docker Hub"
	case "ecr-public":
		return "ECR Public"
	case "gitlab":
		return "GitLab"
	default:
		return provider
	}
}

