+	case "gitlab":
+		return fmt.Sprintf("https://gitlab.com/%s/-/releases/%s", repository, version)
+	default:
+		return ""
+	}
+}
+
+// ProviderLabel returns a human-readable label for a provider.
+func ProviderLabel(provider string) string {
+	switch strings.ToLower(provider) {
+	case "github":
+		return "GitHub"
+	case "dockerhub":
+		return "Docker Hub"
+	case "ecr-public":
+		return "ECR Public"
+	case "gitlab":
+		return "GitLab"
+	default:
+		return provider
+	}
+}
